INSERT INTO `properties` (`id`, `title`, `type`, `status`, `price`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('1', 'Galu Beachfront Acres', 'Land', 'For Sale', 'KSh 45,000,000', 'Galu Beach, Diani', 'Prime 2-acre beachfront parcel in Galu, Diani. Ideal for commercial resort or luxury private holiday villas. Clear title, sandy shore, mature baobab trees.', 'Eneo kuu la ekari 2 mbele ya bahari huko Galu, Diani. Ni bora kwa hoteli ya kibiashara au villa ya kifahari ya likizo ya kibinafsi. Hati safi, pwani ya mchanga, miti mikubwa ya mbuyu.', 'Erstklassiges 2 Hektar großes Strandgrundstück in Galu, Diani. Ideal für ein kommerzielles Resort oder luxuriöse private Ferienvillen. Sauberer Titel, Sandstrand, reife Affenbrotbäume.', 'Splendido terreno di 2 acri fronte mare a Galu, Diani. Ideale per resort commerciale o ville private di lusso. Titolo pulito, spiaggia sabbiosa, alberi di baobab maturi.', 'Superbe parcelle de 2 acres en bord de mer à Galu, Diani. Idéal pour un complexe commercial ou des villas de vacances de luxe privées. Titre propre, plage de sable, baobabs matures.', 'Doskonała 2-akrowa działka bezpośrednio przy plaży Galu w Diani. Idealna pod luksusowy kurort lub prywatne wille wakacyjne. Uregulowany stan prawny, piaszczysty brzeg, dojrzałe baobaby.', 'Beachfront, 2 Acres, Sandy Shore, Ocean Access', 'beachfront_land.png', '2026-06-26 18:23:28');
INSERT INTO `properties` (`id`, `title`, `type`, `status`, `price`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('2', 'Bahari Ocean Breeze Villa', 'Property', 'For Sale', 'KSh 28,000,000', 'Diani Beach Road', 'Exquisite 4-bedroom Swahili-style modern villa with infinity pool, lush tropical gardens, and rooftop terrace. Secure gated community, 5 minutes walk to the beach.', 'Villa ya kipekee ya vyumba 4 ya mtindo wa Kiswahili yenye bwawa la kuogelea, bustani za kitropiki, na rotopu. Eneo salama lenye geti, dakika 5 kutembea hadi pwani.', 'Exquisite moderne Villa mit 4 Schlafzimmern im Swahili-Stil, Infinity-Pool, üppigen tropischen Gärten und Dachterrasse. Sichere Wohnanlage, 5 Gehminuten zum Strand.', 'Splendida villa moderna in stile Swahili con 4 camere da letto, piscina a sfioro, rigogliosi giardini tropicali e terrazza sul tetto. Complesso custodito, a 5 minuti a piedi dalla spiaggia.', 'Superbe villa moderne de 4 chambres de style swahili avec piscine à débordement, jardins tropicaux luxuriants et toit-terrasse. Résidence fermée et sécurisée, à 5 minutes à pied de la plage.', 'Wykwintna, nowoczesna willa w stylu suahili z 4 sypialniami, basenem typu infinity, bujnym ogrodem tropikalnym i tarasem na dachu. Strzeżone osiedle, 5 minut pieszo do plaży.', 'Pool, 4 Bedrooms, Rooftop Terrace, Swahili Design', 'swahili_luxury_villa.png', '2026-06-26 18:23:28');
INSERT INTO `properties` (`id`, `title`, `type`, `status`, `price`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('3', 'Kikambala Heights Residential', 'Development', 'Invested', 'KSh 12,500,000 (Starting)', 'Kikambala, Coastal Highway', 'An emerging gated estate featuring modern 2 & 3 bedroom luxury apartments with panoramic sea views, solar power integration, and high-speed internet.', 'Eneo linalochipuka la makazi lenye vyumba vya kisasa vya kifahari vya vyumba 2 na 3 vilivyo na muonekano wa bahari, umeme wa jua, na mtandao wa kasi.', 'Eine im Bau befindliche Wohnanlage mit modernen Luxusapartments mit 2 und 3 Schlafzimmern, Panoramablick auf das Meer, Solarenergie und Highspeed-Internet.', 'Un complesso residenziale emergente con moderni appartamenti di lusso con 2 e 3 camere da letto con vista panoramica sul mare, energia solare integrata e internet ad alta velocità.', 'Une copropriété résidentielle émergente proposant des appartements de luxe modernes de 2 et 3 chambres avec vue panoramique sur la mer, énergie solaire et internet haut débit.', 'Nowo powstające luksusowe apartamenty z 2 i 3 sypialniami, z panoramicznym widokiem na morze, instalacją fotowoltaiczną i szybkim internetem.', 'Ocean View, Solar Power, Security, Gym & Pool', 'modern_heights_residence.png', '2026-06-26 18:23:28');
INSERT INTO `properties` (`id`, `title`, `type`, `status`, `price`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('4', 'Vipingo Ridge Golf Estate', 'Development', 'For Sale', 'KSh 48,000,000', 'Vipingo Ridge, Kilifi', 'Premium golf villa at Vipingo Ridge. Enjoy access to the 18-hole championship golf course, swimming pools, clubhouse, and private airstrip. Panoramic coastal views.', 'Villa ya gofu ya kiwango cha juu huko Vipingo Ridge. Furahia ufikiaji wa uwanja wa gofu wa mashindano ya mashimo 18, mabwawa ya kuogelea, na uwanja wa ndege wa kibinafsi.', 'Premium-Golfvilla in Vipingo Ridge. Genießen Sie Zugang zum 18-Loch-Meisterschaftsgolfplatz, den Swimmingpools, dem Clubhaus und der privaten Landebahn.', 'Villa da golf premium a Vipingo Ridge. Goditi l\'accesso al campo da golf a 18 buche, piscine, club house e pista di atterraggio privata. Vista panoramica sulla costa.', 'Villa de golf haut de gamme à Vipingo Ridge. Profitez de l\'accès au parcours de golf de championnat de 18 trous, aux piscines, au club-house et à la piste d\'atterrissage.', 'Luksusowa willa przy polu golfowym w Vipingo Ridge. Dostęp do 18-dołkowego mistrzowskiego pola golfowego, basenów, klubu i prywatnego pasa startowego.', 'Golf Course, 4 Bedrooms, Clubhouse, Ocean Views, Security', 'property_care_site.png', '2026-06-26 18:23:28');
INSERT INTO `properties` (`id`, `title`, `type`, `status`, `price`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('5', 'Shela Beach House Retreat', 'Property', 'For Sale', 'KSh 65,000,000', 'Shela, Lamu Island', 'A stunning classic Lamu house situated in Shela. Offers beautifully restored Swahili architecture, spacious open courtyards, and a rooftop with views over the channel.', 'Nyumba nzuri ya kitamaduni ya Lamu iliyopo Shela. Inatoa usanifu ulioboreshwa wa Kiswahili, nyua kubwa za wazi, na rotopu yenye muonekano mzuri wa bahari.', 'Ein atemberaubendes klassisches Lamu-Haus in Shela. Bietet wunderschön restaurierte Swahili-Architektur, weitläufige offene Innenhöfe und eine Dachterrasse.', 'Una splendida casa classica di Lamu situata a Shela. Offre un\'architettura Swahili splendidamente restaurata, ampi cortili aperti e terrazza panoramica.', 'Une superbe maison classique de Lamu située à Shela. Offre une architecture swahili magnifiquement restaurée, de spacieuses cours ouvertes et un toit-terrasse.', 'Wspaniały tradycyjny dom na Lamu w Shela. Pięknie odrestaurowana architektura suahili, przestronne otwarte dziedzińce i taras z widokiem na kanał.', 'Beach View, Swahili Architecture, 5 Bedrooms, Courtyard', 'diani_beach_hero.png', '2026-06-26 18:23:28');
