DROP TABLE IF EXISTS `villas`;
CREATE TABLE `villas` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `price_per_night` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `capacity` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `location` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Diani',
  `description_en` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `description_sw` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `description_de` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `description_it` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `description_fr` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `description_pl` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `features` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `image_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Data Seeding for Table `villas`
INSERT INTO `villas` (`id`, `title`, `price_per_night`, `capacity`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('1', 'Villa Mbuyuni Luxury Retreat', 'KSh 45,000', '8 Guests (4 Bedrooms)', 'Diani Beach Road', 'Stunning ocean-view holiday villa with a private swimming pool, Swahili architecture, dedicated private chef, fully air-conditioned, and manicured private gardens.', 'Villa ya likizo yenye muonekano wa bahari na bwawa la kuogelea la kibinafsi, usanifu wa Kiswahili, mpishi aliyejitolea, viyoyozi, na bustani nzuri ya kibinafsi.', 'Atemberaubende Ferienvilla mit Meerblick, privatem Pool, Swahili-Architektur, eigenem Koch, voll klimatisiert und gepflegten privaten Gärten.', 'Splendida villa per vacanze vista mare con piscina privata, architettura Swahili, chef dedicato, aria condizionata e giardini privati curati.', 'Superbe villa de vacances avec vue sur l\'océan, piscine privée, architecture swahilie, chef privé, climatisation et jardins privés arborés.', 'Wspaniała willa wakacyjna z widokiem na ocean, prywatnym basenem, architekturą w stylu suahili, prywatnym kucharzem, klimatyzacją i zadbanym ogrodem.', 'Private Pool, Personal Chef, AC, WiFi, Beach Access', 'swahili_luxury_villa.png', '2026-06-26 18:50:39');
INSERT INTO `villas` (`id`, `title`, `price_per_night`, `capacity`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('2', 'Bahari Sea Breeze Honeymoon Suite', 'KSh 22,000', '2 Guests (1 Bedroom)', 'Galu Beach, Diani', 'Romantic beachfront cottage designed for couples. Steps away from the ocean, featuring a cozy terrace and local makuti-thatched roof, modern bathroom, and private hot tub.', 'Koti ya pwani ya kimapenzi iliyoundwa kwa wanandoa. Hatua chache kutoka baharini, yenye terasi ya kupumzikia na paa la makuti la kienyeji, na beseni la maji moto la kibinafsi.', 'Romantisches Cottage am Strand für Paare. Nur wenige Schritte vom Meer entfernt, mit gemütlicher Terrasse, traditionellem Makuti-Dach und privatem Whirlpool.', 'Romantico cottage fronte mare progettato per coppie. A pochi passi dall\'oceano, con un\'accogliente terrazza, tetto in makuti locale e vasca idromassaggio privata.', 'Cottage romantique en bord de mer conçu pour les couples. À quelques pas de l\'océan, avec une terrasse confortable, un toit en makuti et un jacuzzi privé.', 'Romantyczny domek przy plaży zaprojektowany dla par. Kilka kroków od oceanu, z przytulnym tarasem, tradycyjnym dachem z makuti i prywatnym jacuzzi.', 'Beachfront, Hot Tub, Makuti Roof, AC, Breakfast Included', 'beachfront_land.png', '2026-06-26 18:50:39');
INSERT INTO `villas` (`id`, `title`, `price_per_night`, `capacity`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('3', 'Kikambala Ocean Vista Penthouse', 'KSh 18,500', '4 Guests (2 Bedrooms)', 'Kikambala Coast', 'Modern luxury penthouse apartment featuring panoramic sea views, solar power integration, high-speed elevator, and shared infinity pool.', 'Ghorofa ya juu ya kifahari ya kisasa yenye muonekano mzuri wa bahari, matumizi ya umeme wa jua, lifti ya mwendo kasi, na bwawa kubwa la kuogelea.', 'Modernes Luxus-Penthouse-Apartment mit Panoramablick auf das Meer, Solarenergie, Highspeed-Aufzug und gemeinsamem Infinity-Pool.', 'Moderno attico di lusso con vista panoramica sul mare, energia solare integrata, ascensore ad alta velocità e piscina a sfioro in comune.', 'Penthouse de luxe moderne avec vue panoramique sur la mer, énergie solaire, ascenseur rapide et piscine à débordement commune.', 'Nowoczesny luksusowy penthouse z panoramicznym widokiem na morze, panelem fotowoltaicznym, windą i wspólnym basenem typu infinity.', 'Sea View, Elevator, Solar Energy, Pool, Gym Access', 'modern_heights_residence.png', '2026-06-26 18:50:39');
INSERT INTO `villas` (`id`, `title`, `price_per_night`, `capacity`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('4', 'Tiwi Cliffs Cliffside Cottage', 'KSh 30,000', '6 Guests (3 Bedrooms)', 'Tiwi Beach', 'Stunning cottage positioned on the cliffs of Tiwi. Enjoy direct beach access, private plunge pool, and local Swahili decor.', 'Koti nzuri iliyopo kwenye majabali ya Tiwi. Furahia ufikiaji wa moja kwa moja wa pwani, bwawa dogo la kibinafsi, na mapambo ya kienyeji ya Kiswahili.', 'Atemberaubendes Cottage auf den Klippen von Tiwi. Genießen Sie direkten Strandzugang, einen privaten Plunge-Pool und traditionelles Swahili-Dekor.', 'Splendido cottage arroccato sulle scogliere di Tiwi. Goditi l\'accesso diretto alla spiaggia, una piccola piscina privata e decorazioni in stile Swahili.', 'Superbe cottage situé sur les falaises de Tiwi. Profitez d\'un accès direct à la plage, d\'une petite piscine privée et d\'une décoration swahilie.', 'Wspaniały domek położony na klifach w Tiwi. Bezpośredni dostęp do plaży, prywatny minibasenu i tradycyjny wystrój suahili.', 'Cliffside, Plunge Pool, Direct Beach Access, Housekeeper', 'diani_beach_hero.png', '2026-06-26 18:50:39');
INSERT INTO `villas` (`id`, `title`, `price_per_night`, `capacity`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('5', 'Shimoni Reef Divers Lodge', 'KSh 12,000', '4 Guests (2 Bedrooms)', 'Shimoni Marine Port', 'Cozy coastal lodge ideal for marine sanctuary visitors and scuba divers. Near Kisite-Mpunguti Marine Park.', 'Loji nzuri ya pwani inayofaa kwa wageni wa hifadhi ya bahari na wapiga mbizi. Karibu na Hifadhi ya Bahari ya Kisite-Mpunguti.', 'Gemütliche Küstenlodge, ideal für Besucher des Meeresschutzgebiets und Taucher. In der Nähe des Kisite-Mpunguti-Meeresparks.', 'Accogliente lodge costiero ideale per visitatori del santuario marino e subacquei. Vicino al Parco Marino Kisite-Mpunguti.', 'Lodge côtier confortable idéal pour les visiteurs du sanctuaire marin et les plongeurs. Près du parc marin de Kisite-Mpunguti.', 'Przytulny domek na wybrzeżu, idealny dla nurków i turystów odwiedzających sanktuarium morskie. Blisko Parku Morskiego Kisite-Mpunguti.', 'Near Marine Park, Boat Trips, Scuba Support, Ocean Breeze', 'property_care_site.png', '2026-06-26 18:50:39');
INSERT INTO `villas` (`id`, `title`, `price_per_night`, `capacity`, `location`, `description_en`, `description_sw`, `description_de`, `description_it`, `description_fr`, `description_pl`, `features`, `image_url`, `created_at`) VALUES ('6', 'Msambweni Palm Oasis Villa', 'KSh 38,000', '8 Guests (4 Bedrooms)', 'Msambweni Coast', 'Secluded eco-friendly luxury villa surrounded by palm forests. Private beach cove access and private chef services.', 'Villa ya kifahari na ya kirafiki kwa mazingira iliyozungukwa na misitu ya minazi. Ufikiaji wa pwani ya kibinafsi na huduma za mpishi.', 'Abgeschiedene umweltfreundliche Luxusvilla umgeben von Palmenwäldern. Zugang zu einer privaten Bucht und Kochservice.', 'Villa di lusso ecologica e appartata circondata da palmeti. Accesso privato alla caletta e servizi di uno chef privato.', 'Villa de luxe écologique et isolée entourée de palmeraies. Accès à une crique privée et services d\'un chef cuisinier.', 'Ustronna, ekologiczna luksusowa willa otoczona lasem palmowym. Dostęp do prywatnej zatoczki i usługi prywatnego kucharza.', 'Private Cove, Solar Powered, Eco-friendly, Chef, Pool', 'swahili_luxury_villa.png', '2026-06-26 18:50:39');

DROP TABLE IF EXISTS `inquiries`;
CREATE TABLE `inquiries` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `subject` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `message` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `division` enum('General','Estates','Care','Hospitality') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'General',
  `reference_id` int DEFAULT NULL,
  `status` enum('New','Read','Replied') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'New',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `bookings`;
CREATE TABLE `bookings` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `service_type` enum('Care','Hospitality') COLLATE utf8mb4_unicode_ci NOT NULL,
  `service_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `preferred_date` date NOT NULL,
  `details` text COLLATE utf8mb4_unicode_ci,
  `status` enum('Pending','Confirmed','Completed','Cancelled') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Pending',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

SET FOREIGN_KEY_CHECKS=1;
